var COURSE_TR_PT = [{day: 1, title: `İlk selamlaşmalar`, title_native: `Primeiros cumprimentos`, focus: `Lizbon’a yeni vardığında ilk ihtiyacın insanlarla kibarca selamlaşmak ve basitçe kendini tanıtmaktır. Bugün Portekizceye güvenli bir başlangıç yapacaksın.`, vocab: [{pt: `olá`, tr: `merhaba`, ipa: `o-LA`},{pt: `bom dia`, tr: `günaydın / iyi günler`, ipa: `bom Dİ-a`},{pt: `boa tarde`, tr: `iyi öğleden sonra`, ipa: `BO-a TAR-ci`},{pt: `boa noite`, tr: `iyi akşamlar / iyi geceler`, ipa: `BO-a NOY-ti`},{pt: `tchau`, tr: `hoşça kal`, ipa: `ÇAU`},{pt: `por favor`, tr: `lütfen`, ipa: `por fa-VOR`},{pt: `obrigado`, tr: `teşekkür ederim erkek söyleyen`, ipa: `ob-ri-GA-du`},{pt: `obrigada`, tr: `teşekkür ederim kadın söyleyen`, ipa: `ob-ri-GA-da`},{pt: `sim`, tr: `evet`, ipa: `sin`},{pt: `não`, tr: `hayır`, ipa: `nau`}], phrases: [{pt: `Olá, bom dia.`, tr: `Merhaba, günaydın.`, ipa: `o-LA, bom Dİ-a`},{pt: `Como vai?`, tr: `Nasılsınız?`, ipa: `KO-mu vay`},{pt: `Estou bem, obrigado.`, tr: `İyiyim, teşekkür ederim.`, ipa: `iş-TOU bayn, ob-ri-GA-du`},{pt: `Muito prazer.`, tr: `Memnun oldum.`, ipa: `MUY-tu pra-ZER`},{pt: `Até logo.`, tr: `Sonra görüşürüz.`, ipa: `a-TE LO-gu`},{pt: `Por favor, fale devagar.`, tr: `Lütfen yavaş konuşun.`, ipa: `por fa-VOR, FA-li dı-va-GAR`}], grammar: `Portekizcede selamlaşmalar günün saatine göre değişir: bom dia sabah ve öğlen civarı, boa tarde öğleden sonra, boa noite akşam ve gece kullanılır. “Obrigado” erkek konuşmacı, “obrigada” kadın konuşmacı tarafından söylenir. Brezilya’da telaffuz biraz daha açık, Portekiz’de ise bazı sesler daha kapalı duyulabilir.`, practice: [`Portekizce “merhaba” ve “lütfen” de.`,`Sabah bir kafeye girdiğini düşün ve uygun selamı kur.`,`“İyiyim, teşekkür ederim” cümlesini kendi cinsiyetine göre söyle.`,`Birine “lütfen yavaş konuşun” demeyi çalış.`,`Gün içinde üç farklı saat için doğru selamı seç.`]},{day: 2, title: `Kendini tanıtma`, title_native: `Apresentar-se`, focus: `Porto’da bir hostelde ya da turda yeni insanlarla tanışırken adını, nereli olduğunu ve kısa bir kişisel bilgiyi söylemen gerekir.`, vocab: [{pt: `nome`, tr: `isim`, ipa: `NO-mi`},{pt: `eu`, tr: `ben`, ipa: `eu`},{pt: `você`, tr: `sen / siz`, ipa: `vo-SE`},{pt: `sou`, tr: `-im / -ım`, ipa: `sou`},{pt: `turco`, tr: `Türk erkek`, ipa: `TUR-ku`},{pt: `turca`, tr: `Türk kadın`, ipa: `TUR-ka`},{pt: `Türkiye`, tr: `Türkiye`, ipa: `tur-Kİ-ya`},{pt: `amigo`, tr: `arkadaş erkek`, ipa: `a-Mİ-gu`},{pt: `amiga`, tr: `arkadaş kadın`, ipa: `a-Mİ-ga`},{pt: `aqui`, tr: `burada`, ipa: `a-Kİ`}], phrases: [{pt: `Eu sou da Turquia.`, tr: `Ben Türkiye’denim.`, ipa: `eu sou da tur-Kİ-ya`},{pt: `Meu nome é Emre.`, tr: `Benim adım Emre.`, ipa: `meu NO-mi e EM-ri`},{pt: `Qual é o seu nome?`, tr: `Adınız ne?`, ipa: `kwal e u seu NO-mi`},{pt: `Sou turista.`, tr: `Turistim.`, ipa: `sou tu-RİŞ-ta`},{pt: `Estou aqui por três dias.`, tr: `Üç günlüğüne buradayım.`, ipa: `iş-TOU a-Kİ por treyş Dİ-aş`},{pt: `Prazer em conhecer você.`, tr: `Sizinle tanıştığıma memnun oldum.`, ipa: `pra-ZER en ko-nye-SER vo-SE`}], grammar: `“Eu sou” kalıcı kimlikler için kullanılır: milliyet, meslek, ad gibi. “Estou” ise geçici durumlar ve yerler için kullanılır: buradayım, iyiyim, yorgunum gibi. Seyahatte “sou da Turquia” ve “estou aqui” ikilisi çok işine yarar.`, practice: [`Kendi adını kullanarak “Benim adım...” cümlesini kur.`,`“Ben Türkiye’denim” cümlesini üç kez yüksek sesle söyle.`,`Birine adını sormayı dene.`,`“Ben turistim” cümlesini yaz.`,`“Buradayım” anlamındaki ifadeyi hatırla ve bir cümlede kullan.`]},{day: 3, title: `Sayılar ve fiyatlar`, title_native: `Números e preços`, focus: `Rio de Janeiro’da pazarda, Lizbon’da tramvayda veya Luanda’da takside fiyat anlamak için sayılar çok önemlidir.`, vocab: [{pt: `um`, tr: `bir`, ipa: `um`},{pt: `dois`, tr: `iki`, ipa: `doyş`},{pt: `três`, tr: `üç`, ipa: `treyş`},{pt: `quatro`, tr: `dört`, ipa: `KWA-tru`},{pt: `cinco`, tr: `beş`, ipa: `SİN-ku`},{pt: `seis`, tr: `altı`, ipa: `seyş`},{pt: `sete`, tr: `yedi`, ipa: `SE-ti`},{pt: `oito`, tr: `sekiz`, ipa: `OY-tu`},{pt: `nove`, tr: `dokuz`, ipa: `NO-vi`},{pt: `dez`, tr: `on`, ipa: `deş`}], phrases: [{pt: `Quanto custa?`, tr: `Ne kadar?`, ipa: `KWAN-tu KUŞ-ta`},{pt: `Custa dez euros.`, tr: `On avro tutuyor.`, ipa: `KUŞ-ta deş EU-ruş`},{pt: `Só um, por favor.`, tr: `Sadece bir tane, lütfen.`, ipa: `so um, por fa-VOR`},{pt: `Dois bilhetes, por favor.`, tr: `İki bilet, lütfen.`, ipa: `doyş bi-LYE-tiş, por fa-VOR`},{pt: `É muito caro.`, tr: `Çok pahalı.`, ipa: `e MUY-tu KA-ru`},{pt: `Tem troco?`, tr: `Bozuk paranız var mı?`, ipa: `ten TRO-ku`}], grammar: `Portekizcede “quanto custa?” tekil ürünler için “ne kadar tutuyor?” demektir. “Quanto custam?” çoğul ürünler için kullanılır ama seyahatte çoğu zaman “quanto custa?” ile anlaşılabilirsin. Para birimi ülkeye göre değişir: Portekiz’de euro, Brezilya’da real kullanılır.`, practice: [`1’den 10’a kadar Portekizce say.`,`Bir pazarda “ne kadar?” diye sorduğunu hayal et.`,`“İki bilet, lütfen” cümlesini söyle.`,`“Çok pahalı” ifadesini kullanarak kısa bir tepki ver.`,`Duyduğun fiyatı tekrar etmek için üç sayı seç.`]},{day: 4, title: `Kibar istekler`, title_native: `Pedidos educados`, focus: `Coimbra’da bir kafede veya Salvador’da küçük bir dükkânda nazik olmak iletişimi kolaylaştırır. Bugün istek kurmayı öğreneceksin.`, vocab: [{pt: `quero`, tr: `istiyorum`, ipa: `KE-ru`},{pt: `queria`, tr: `isterdim`, ipa: `ke-Rİ-a`},{pt: `água`, tr: `su`, ipa: `A-gwa`},{pt: `café`, tr: `kahve`, ipa: `ka-FE`},{pt: `menu`, tr: `menü`, ipa: `me-NU`},{pt: `conta`, tr: `hesap`, ipa: `KON-ta`},{pt: `ajuda`, tr: `yardım`, ipa: `a-JU-da`},{pt: `desculpe`, tr: `affedersiniz`, ipa: `deş-KUL-pi`},{pt: `licença`, tr: `izin`, ipa: `li-SEN-sa`},{pt: `agora`, tr: `şimdi`, ipa: `a-GO-ra`}], phrases: [{pt: `Queria um café, por favor.`, tr: `Bir kahve isterdim, lütfen.`, ipa: `ke-Rİ-a um ka-FE, por fa-VOR`},{pt: `Quero água, por favor.`, tr: `Su istiyorum, lütfen.`, ipa: `KE-ru A-gwa, por fa-VOR`},{pt: `A conta, por favor.`, tr: `Hesap, lütfen.`, ipa: `a KON-ta, por fa-VOR`},{pt: `Desculpe, preciso de ajuda.`, tr: `Affedersiniz, yardıma ihtiyacım var.`, ipa: `deş-KUL-pi, pre-Sİ-zu dı a-JU-da`},{pt: `Com licença.`, tr: `Müsaadenizle.`, ipa: `kon li-SEN-sa`},{pt: `Pode repetir?`, tr: `Tekrar eder misiniz?`, ipa: `PO-ci he-pe-ÇİR`}], grammar: `“Queria” doğrudan “istiyordum” anlamına gelse de hizmet ortamlarında “isterdim” gibi nazik bir istektir. “Quero” daha doğrudandır ve yanlış değildir, ama restoran ve kafelerde “queria” daha yumuşak duyulur. “Por favor” eklemek her zaman iyi bir fikirdir.`, practice: [`“Bir kahve isterdim” cümlesini kur.`,`Bir garsona hesap istemeyi çalış.`,`“Affedersiniz, yardıma ihtiyacım var” de.`,`“Quero” ve “queria” arasındaki ton farkını Türkçe açıkla.`,`Bugünkü kelimelerle üç kibar istek yaz.`]},{day: 5, title: `Yol sorma`, title_native: `Pedir direções`, focus: `Lizbon’un Alfama sokaklarında veya Porto’nun yokuşlarında kaybolmak çok kolaydır. Bugün yön sormayı ve basit tarifleri anlamayı öğreneceksin.`, vocab: [{pt: `rua`, tr: `sokak`, ipa: `HU-a`},{pt: `avenida`, tr: `cadde`, ipa: `a-ve-Nİ-da`},{pt: `praça`, tr: `meydan`, ipa: `PRA-sa`},{pt: `direita`, tr: `sağ`, ipa: `ci-REY-ta`},{pt: `esquerda`, tr: `sol`, ipa: `iş-KER-da`},{pt: `em frente`, tr: `düz ileri`, ipa: `en FREN-çi`},{pt: `perto`, tr: `yakın`, ipa: `PER-tu`},{pt: `longe`, tr: `uzak`, ipa: `LON-ji`},{pt: `estação`, tr: `istasyon`, ipa: `iş-ta-SAU`},{pt: `mapa`, tr: `harita`, ipa: `MA-pa`}], phrases: [{pt: `Onde fica a estação?`, tr: `İstasyon nerede?`, ipa: `ON-ci Fİ-ka a iş-ta-SAU`},{pt: `É perto daqui?`, tr: `Buraya yakın mı?`, ipa: `e PER-tu da-Kİ`},{pt: `Vire à direita.`, tr: `Sağa dönün.`, ipa: `Vİ-ri a ci-REY-ta`},{pt: `Vire à esquerda.`, tr: `Sola dönün.`, ipa: `Vİ-ri a iş-KER-da`},{pt: `Siga em frente.`, tr: `Düz devam edin.`, ipa: `Sİ-ga en FREN-çi`},{pt: `Pode mostrar no mapa?`, tr: `Haritada gösterebilir misiniz?`, ipa: `PO-ci moş-TRAR nu MA-pa`}], grammar: `“Onde fica...?” bir yerin konumunu sormak için çok kullanılır. “Ficar” burada “bulunmak” anlamındadır. Tariflerde emir gibi duyulan “siga” ve “vire” kibar yönlendirme kalıplarıdır.`, practice: [`“İstasyon nerede?” cümlesini söyle.`,`Sağ, sol ve düz kelimelerini ezberden tekrar et.`,`Haritada göstermesini istemeyi çalış.`,`Bir otelin meydana yakın olup olmadığını sor.`,`Hayali bir rota için üç kısa yön cümlesi kur.`]},{day: 6, title: `Ulaşım ve biletler`, title_native: `Transporte e bilhetes`, focus: `Porto metrosunda, Lizbon tramvayında ya da São Paulo otobüsünde bilet almak ve doğru aracı bulmak gerekir.`, vocab: [{pt: `bilhete`, tr: `bilet`, ipa: `bi-LYE-ti`},{pt: `comboio`, tr: `tren`, ipa: `kon-BOY-u`},{pt: `metrô`, tr: `metro`, ipa: `me-TRO`},{pt: `autocarro`, tr: `otobüs Portekiz`, ipa: `au-to-KA-hu`},{pt: `ônibus`, tr: `otobüs Brezilya`, ipa: `O-ni-bus`},{pt: `táxi`, tr: `taksi`, ipa: `TAK-si`},{pt: `paragem`, tr: `durak Portekiz`, ipa: `pa-RA-jen`},{pt: `ponto`, tr: `durak Brezilya`, ipa: `PON-tu`},{pt: `ida`, tr: `gidiş`, ipa: `İ-da`},{pt: `volta`, tr: `dönüş`, ipa: `VOL-ta`}], phrases: [{pt: `Um bilhete para Lisboa, por favor.`, tr: `Lizbon’a bir bilet, lütfen.`, ipa: `um bi-LYE-ti PA-ra liş-BO-a, por fa-VOR`},{pt: `É só ida?`, tr: `Sadece gidiş mi?`, ipa: `e so İ-da`},{pt: `Ida e volta, por favor.`, tr: `Gidiş dönüş, lütfen.`, ipa: `İ-da i VOL-ta, por fa-VOR`},{pt: `Onde é a paragem?`, tr: `Durak nerede?`, ipa: `ON-ci e a pa-RA-jen`},{pt: `Este metrô vai para o centro?`, tr: `Bu metro merkeze gider mi?`, ipa: `EŞ-ti me-TRO vay PA-ra u SEN-tru`},{pt: `Quanto tempo demora?`, tr: `Ne kadar sürer?`, ipa: `KWAN-tu TEM-pu de-MO-ra`}], grammar: `Portekiz ve Brezilya ulaşım kelimelerinde farklar vardır. Portekiz’de “autocarro” ve “paragem”, Brezilya’da “ônibus” ve “ponto” daha yaygındır. “Vai para...” kalıbı “...e gider mi?” anlamında çok pratik bir seyahat kalıbıdır.`, practice: [`Gideceğin şehir adıyla bilet isteme cümlesi kur.`,`“Gidiş dönüş” ifadesini Portekizce söyle.`,`Metro merkeze gidiyor mu diye sor.`,`“Ne kadar sürer?” cümlesini ulaşım bağlamında kullan.`,`Portekiz ve Brezilya otobüs kelimelerini karşılaştır.`]},{day: 7, title: `Otelde giriş işlemleri`, title_native: `Check-in no hotel`, focus: `Braga’da küçük bir otelde veya Rio’da sahil yakınında bir konaklamada resepsiyonla temel bilgileri paylaşman gerekir.`, vocab: [{pt: `hotel`, tr: `otel`, ipa: `o-TEL`},{pt: `reserva`, tr: `rezervasyon`, ipa: `he-ZER-va`},{pt: `quarto`, tr: `oda`, ipa: `KWAR-tu`},{pt: `passaporte`, tr: `pasaport`, ipa: `pa-sa-POR-çi`},{pt: `chave`, tr: `anahtar`, ipa: `ŞA-vi`},{pt: `cartão`, tr: `kart`, ipa: `kar-TAU`},{pt: `noite`, tr: `gece`, ipa: `NOY-çi`},{pt: `cama`, tr: `yatak`, ipa: `KA-ma`},{pt: `banheiro`, tr: `banyo Brezilya`, ipa: `ba-NYEY-ru`},{pt: `casa de banho`, tr: `banyo Portekiz`, ipa: `KA-za dı BAN-yu`}], phrases: [{pt: `Tenho uma reserva.`, tr: `Rezervasyonum var.`, ipa: `TEN-yu U-ma he-ZER-va`},{pt: `Meu nome é Can.`, tr: `Benim adım Can.`, ipa: `meu NO-mi e jan`},{pt: `Aqui está meu passaporte.`, tr: `Pasaportum burada.`, ipa: `a-Kİ iş-TA meu pa-sa-POR-çi`},{pt: `Qual é o número do quarto?`, tr: `Oda numarası kaç?`, ipa: `kwal e u NU-me-ru du KWAR-tu`},{pt: `O café da manhã está incluído?`, tr: `Kahvaltı dahil mi?`, ipa: `u ka-FE da ma-NYA iş-TA in-klu-İ-du`},{pt: `A que horas é o check-out?`, tr: `Check-out saat kaçta?`, ipa: `a ki O-raş e u çek-AUT`}], grammar: `“Tenho” fiili “sahibim / var” anlamına gelir ve seyahatte çok kullanılır: tenho reserva, tenho passaporte, tenho uma pergunta. Otelde “está incluído?” kalıbı bir şeyin fiyata dahil olup olmadığını sormak için kullanılır. Portekiz’de kahvaltı için “pequeno-almoço” da duyabilirsin.`, practice: [`“Rezervasyonum var” cümlesini söyle.`,`Kendi adınla otelde giriş cümlesi kur.`,`Kahvaltının dahil olup olmadığını sor.`,`Oda numarasını sormayı çalış.`,`Check-out saatini sormak için cümleyi tekrar et.`]},{day: 8, title: `Kafede sipariş`, title_native: `Pedir no café`, focus: `Lizbon’da pastel de nata yanında kahve sipariş ederken kısa ve doğal kalıplar çok işe yarar.`, vocab: [{pt: `café`, tr: `kahve`, ipa: `ka-FE`},{pt: `leite`, tr: `süt`, ipa: `LEY-çi`},{pt: `açúcar`, tr: `şeker`, ipa: `a-SU-kar`},{pt: `chá`, tr: `çay`, ipa: `şa`},{pt: `pastel`, tr: `tatlı / hamur işi`, ipa: `paş-TEL`},{pt: `mesa`, tr: `masa`, ipa: `ME-za`},{pt: `copo`, tr: `bardak`, ipa: `KO-pu`},{pt: `xícara`, tr: `fincan Brezilya`, ipa: `Şİ-ka-ra`},{pt: `chávena`, tr: `fincan Portekiz`, ipa: `ŞA-ve-na`},{pt: `frio`, tr: `soğuk`, ipa: `FRİ-u`}], phrases: [{pt: `Queria um café com leite.`, tr: `Sütlü kahve isterdim.`, ipa: `ke-Rİ-a um ka-FE kon LEY-çi`},{pt: `Sem açúcar, por favor.`, tr: `Şekersiz, lütfen.`, ipa: `sen a-SU-kar, por fa-VOR`},{pt: `Para levar ou para aqui?`, tr: `Paket mi, burada mı?`, ipa: `PA-ra le-VAR ou PA-ra a-Kİ`},{pt: `Para aqui, por favor.`, tr: `Burada, lütfen.`, ipa: `PA-ra a-Kİ, por fa-VOR`},{pt: `Tem chá frio?`, tr: `Soğuk çay var mı?`, ipa: `ten şa FRİ-u`},{pt: `Mais uma água, por favor.`, tr: `Bir su daha, lütfen.`, ipa: `mayş U-ma A-gwa, por fa-VOR`}], grammar: `“Com” ile “ile”, “sem” ile “-siz” anlamı verilir: com leite, sem açúcar. Sipariş verirken “queria” kullanmak nazik ve doğal bir seçimdir. “Mais uma” bir tane daha demektir ve kafelerde çok pratik bir kalıptır.`, practice: [`Sütlü kahve sipariş et.`,`Şekersiz istediğini söyle.`,`Paket mi burada mı sorusuna cevap ver.`,`Bir su daha istemeyi çalış.`,`“Com” ve “sem” ile üç küçük ifade yaz.`]},{day: 9, title: `Restoranda yemek seçme`, title_native: `Escolher comida no restaurante`, focus: `São Paulo’da bir restoranda ya da Porto’da geleneksel bir lokantada menüyü anlamak ve tercih belirtmek önemlidir.`, vocab: [{pt: `comida`, tr: `yemek`, ipa: `ko-Mİ-da`},{pt: `prato`, tr: `yemek / tabak`, ipa: `PRA-tu`},{pt: `carne`, tr: `et`, ipa: `KAR-ni`},{pt: `frango`, tr: `tavuk`, ipa: `FRAN-gu`},{pt: `peixe`, tr: `balık`, ipa: `PEY-şi`},{pt: `arroz`, tr: `pirinç`, ipa: `a-HOŞ`},{pt: `salada`, tr: `salata`, ipa: `sa-LA-da`},{pt: `sopa`, tr: `çorba`, ipa: `SO-pa`},{pt: `pão`, tr: `ekmek`, ipa: `pau`},{pt: `sobremesa`, tr: `tatlı`, ipa: `so-bri-ME-za`}], phrases: [{pt: `O que recomenda?`, tr: `Ne önerirsiniz?`, ipa: `u ki he-ko-MEN-da`},{pt: `Queria o prato do dia.`, tr: `Günün yemeğini isterdim.`, ipa: `ke-Rİ-a u PRA-tu du Dİ-a`},{pt: `Tem opção vegetariana?`, tr: `Vejetaryen seçenek var mı?`, ipa: `ten op-SAU ve-je-ta-Rİ-a-na`},{pt: `Não como carne.`, tr: `Et yemiyorum.`, ipa: `nau KO-mu KAR-ni`},{pt: `Está delicioso.`, tr: `Çok lezzetli.`, ipa: `iş-TA de-li-Sİ-o-zu`},{pt: `Posso ver o menu?`, tr: `Menüyü görebilir miyim?`, ipa: `PO-su ver u me-NU`}], grammar: `“Não como...” kalıbı “... yemiyorum” demektir ve diyet tercihleri için kullanılır. “Tem opção...?” bir seçenek olup olmadığını sormanın basit yoludur. “O prato do dia” özellikle Portekiz’de uygun fiyatlı günlük yemek anlamında sık duyulur.`, practice: [`Menüyü görmek istediğini söyle.`,`Vejetaryen seçenek sor.`,`“Et yemiyorum” cümlesini kur.`,`Garsona öneri sormayı çalış.`,`Yemeği beğendiğini söyleyen bir cümle yaz.`]},{day: 10, title: `Alışverişte temel ifadeler`, title_native: `Compras básicas`, focus: `Lizbon’daki bir hediyelik eşya dükkânında ya da Rio’daki pazarda ürün sormayı, fiyat öğrenmeyi ve ödeme yapmayı öğreneceksin.`, vocab: [{pt: `loja`, tr: `mağaza`, ipa: `LO-ja`},{pt: `mercado`, tr: `pazar / market`, ipa: `mer-KA-du`},{pt: `preço`, tr: `fiyat`, ipa: `PRE-su`},{pt: `barato`, tr: `ucuz`, ipa: `ba-RA-tu`},{pt: `caro`, tr: `pahalı`, ipa: `KA-ru`},{pt: `dinheiro`, tr: `nakit`, ipa: `ci-NYEY-ru`},{pt: `cartão`, tr: `kart`, ipa: `kar-TAU`},{pt: `saco`, tr: `poşet`, ipa: `SA-ku`},{pt: `tamanho`, tr: `beden / boyut`, ipa: `ta-MAN-yu`},{pt: `cor`, tr: `renk`, ipa: `kor`}], phrases: [{pt: `Quanto custa isto?`, tr: `Bu ne kadar?`, ipa: `KWAN-tu KUŞ-ta İŞ-tu`},{pt: `Tem em outro tamanho?`, tr: `Başka bedeni var mı?`, ipa: `ten en O-tru ta-MAN-yu`},{pt: `Posso pagar com cartão?`, tr: `Kartla ödeyebilir miyim?`, ipa: `PO-su pa-GAR kon kar-TAU`},{pt: `Tem uma sacola?`, tr: `Poşetiniz var mı?`, ipa: `ten U-ma sa-KO-la`},{pt: `Estou só olhando.`, tr: `Sadece bakıyorum.`, ipa: `iş-TOU so o-LYAN-du`},{pt: `Vou levar este.`, tr: `Bunu alacağım.`, ipa: `vou le-VAR EŞ-ti`}], grammar: `“Este” konuşana yakın olan “bu” anlamına gelir; “isto” ise genel olarak “bu şey” gibi kullanılır. Mağazada sadece bakıyorsan “estou só olhando” kibar ve rahatlatıcıdır. “Vou levar...” kelimesi kelimesine “götüreceğim” olsa da alışverişte “bunu alacağım” demektir.`, practice: [`Bir ürünün fiyatını sor.`,`Kartla ödeme yapıp yapamayacağını sor.`,`“Sadece bakıyorum” cümlesini tekrar et.`,`Başka beden istemeyi çalış.`,`Üç renk veya beden hayal edip alışveriş cümlesi kur.`]},{day: 11, title: `Saat ve zaman`, title_native: `Horas e tempo`, focus: `Tren saatini, müze kapanışını veya restoran rezervasyonunu anlamak için saat ifadeleri gerekir.`, vocab: [{pt: `hora`, tr: `saat`, ipa: `O-ra`},{pt: `minuto`, tr: `dakika`, ipa: `mi-NU-tu`},{pt: `hoje`, tr: `bugün`, ipa: `O-ji`},{pt: `amanhã`, tr: `yarın`, ipa: `a-ma-NYAN`},{pt: `ontem`, tr: `dün`, ipa: `ON-ten`},{pt: `cedo`, tr: `erken`, ipa: `SE-du`},{pt: `tarde`, tr: `geç`, ipa: `TAR-ci`},{pt: `agora`, tr: `şimdi`, ipa: `a-GO-ra`},{pt: `depois`, tr: `sonra`, ipa: `de-POYŞ`},{pt: `antes`, tr: `önce`, ipa: `AN-tiş`}], phrases: [{pt: `Que horas são?`, tr: `Saat kaç?`, ipa: `ki O-raş sau`},{pt: `É uma hora.`, tr: `Saat bir.`, ipa: `e U-ma O-ra`},{pt: `São duas horas.`, tr: `Saat iki.`, ipa: `sau DU-aş O-raş`},{pt: `A que horas abre?`, tr: `Saat kaçta açılıyor?`, ipa: `a ki O-raş A-bri`},{pt: `A que horas fecha?`, tr: `Saat kaçta kapanıyor?`, ipa: `a ki O-raş FE-şa`},{pt: `Volto mais tarde.`, tr: `Daha sonra dönerim.`, ipa: `VOL-tu mayş TAR-ci`}], grammar: `Saat bir için “é uma hora”, diğer saatler için “são duas/três...” kullanılır. “A que horas...?” belirli bir eylemin saatini sormak içindir. Açılış ve kapanış için “abre” ve “fecha” kelimeleri seyahatte çok kullanışlıdır.`, practice: [`“Saat kaç?” diye sor.`,`Saat iki ve saat beş ifadelerini söyle.`,`Bir müzenin kaçta açıldığını sor.`,`Bir mağazanın kaçta kapandığını sor.`,`“Daha sonra dönerim” cümlesini bir alışveriş durumunda kullan.`]},{day: 12, title: `Günler ve plan yapmak`, title_native: `Dias e planos`, focus: `Portekiz’de bir tur rezervasyonu veya Brezilya’da arkadaşla buluşma planlarken günleri ve basit gelecek ifadelerini kullanırsın.`, vocab: [{pt: `segunda-feira`, tr: `pazartesi`, ipa: `se-GUN-da FEY-ra`},{pt: `terça-feira`, tr: `salı`, ipa: `TER-sa FEY-ra`},{pt: `quarta-feira`, tr: `çarşamba`, ipa: `KWAR-ta FEY-ra`},{pt: `quinta-feira`, tr: `perşembe`, ipa: `KİN-ta FEY-ra`},{pt: `sexta-feira`, tr: `cuma`, ipa: `SEŞ-ta FEY-ra`},{pt: `sábado`, tr: `cumartesi`, ipa: `SA-ba-du`},{pt: `domingo`, tr: `pazar`, ipa: `do-MİN-gu`},{pt: `semana`, tr: `hafta`, ipa: `se-MA-na`},{pt: `fim de semana`, tr: `hafta sonu`, ipa: `fin dı se-MA-na`},{pt: `plano`, tr: `plan`, ipa: `PLA-nu`}], phrases: [{pt: `Tenho planos amanhã.`, tr: `Yarın planlarım var.`, ipa: `TEN-yu PLA-nuş a-ma-NYAN`},{pt: `Estou livre no sábado.`, tr: `Cumartesi boşum.`, ipa: `iş-TOU Lİ-vri nu SA-ba-du`},{pt: `Podemos ir na sexta?`, tr: `Cuma gidebilir miyiz?`, ipa: `po-DE-muş ir na SEŞ-ta`},{pt: `Que dia é hoje?`, tr: `Bugün günlerden ne?`, ipa: `ki Dİ-a e O-ji`},{pt: `Até amanhã.`, tr: `Yarın görüşürüz.`, ipa: `a-TE a-ma-NYAN`},{pt: `No fim de semana, vou viajar.`, tr: `Hafta sonu seyahat edeceğim.`, ipa: `nu fin dı se-MA-na, vou vi-a-JAR`}], grammar: `Gün adları Portekizcede genellikle küçük harfle yazılır. “Na sexta” cuma günü, “no sábado” cumartesi günü anlamına gelir. “Vou + fiil” yakın gelecek için çok kullanılır: vou viajar, vou comer, vou descansar.`, practice: [`Haftanın günlerini sırayla söyle.`,`Cumartesi boş olduğunu söyle.`,`Cuma günü gitmeyi öner.`,`Hafta sonu seyahat edeceğini yaz.`,`Bugünün gününü Portekizce sormayı çalış.`]},{day: 13, title: `Hava durumu`, title_native: `Tempo e clima`, focus: `Lizbon sahilinde yürüyüşe çıkmadan veya Rio’da plaja gitmeden önce hava durumunu konuşmak işine yarar.`, vocab: [{pt: `tempo`, tr: `hava durumu / zaman`, ipa: `TEM-pu`},{pt: `sol`, tr: `güneş`, ipa: `sol`},{pt: `chuva`, tr: `yağmur`, ipa: `ŞU-va`},{pt: `vento`, tr: `rüzgar`, ipa: `VEN-tu`},{pt: `calor`, tr: `sıcak`, ipa: `ka-LOR`},{pt: `frio`, tr: `soğuk`, ipa: `FRİ-u`},{pt: `nublado`, tr: `bulutlu`, ipa: `nu-BLA-du`},{pt: `praia`, tr: `plaj`, ipa: `PRA-ya`},{pt: `guarda-chuva`, tr: `şemsiye`, ipa: `GWAR-da ŞU-va`},{pt: `casaco`, tr: `mont`, ipa: `ka-ZA-ku`}], phrases: [{pt: `Como está o tempo?`, tr: `Hava nasıl?`, ipa: `KO-mu iş-TA u TEM-pu`},{pt: `Está sol.`, tr: `Güneşli.`, ipa: `iş-TA sol`},{pt: `Está chovendo.`, tr: `Yağmur yağıyor.`, ipa: `iş-TA şu-VEN-du`},{pt: `Está muito quente.`, tr: `Çok sıcak.`, ipa: `iş-TA MUY-tu KEN-çi`},{pt: `Está frio hoje.`, tr: `Bugün hava soğuk.`, ipa: `iş-TA FRİ-u O-ji`},{pt: `Preciso de um guarda-chuva.`, tr: `Bir şemsiyeye ihtiyacım var.`, ipa: `pre-Sİ-zu dı um GWAR-da ŞU-va`}], grammar: `Hava durumu için çoğunlukla “está” kullanılır çünkü geçici bir durumdan bahsedilir. “Está chovendo” Brezilya’da çok doğal, Portekiz’de “está a chover” de duyabilirsin. “Preciso de...” ihtiyacı ifade eder ve seyahatte çok faydalıdır.`, practice: [`Havanın nasıl olduğunu sor.`,`“Güneşli” ve “yağmur yağıyor” ifadelerini söyle.`,`Çok sıcak olduğunu belirt.`,`Şemsiyeye ihtiyacın olduğunu söyle.`,`Bugünkü gerçek hava durumunu Portekizce anlat.`]},{day: 14, title: `Acil ve önemli ifadeler`, title_native: `Frases importantes e emergência`, focus: `Seyahatte sorun yaşarsan net, kısa ve anlaşılır konuşmak gerekir. Bugün acil durumlarda kullanabileceğin temel ifadeleri öğreneceksin.`, vocab: [{pt: `ajuda`, tr: `yardım`, ipa: `a-JU-da`},{pt: `emergência`, tr: `acil durum`, ipa: `e-mer-JEN-si-a`},{pt: `médico`, tr: `doktor`, ipa: `ME-ci-ku`},{pt: `polícia`, tr: `polis`, ipa: `po-Lİ-si-a`},{pt: `hospital`, tr: `hastane`, ipa: `os-pi-TAL`},{pt: `farmácia`, tr: `eczane`, ipa: `far-MA-si-a`},{pt: `perdido`, tr: `kayıp / kaybolmuş erkek`, ipa: `per-Cİ-du`},{pt: `perdida`, tr: `kayıp / kaybolmuş kadın`, ipa: `per-Cİ-da`},{pt: `dor`, tr: `ağrı`, ipa: `dor`},{pt: `problema`, tr: `sorun`, ipa: `pro-BLE-ma`}], phrases: [{pt: `Preciso de ajuda.`, tr: `Yardıma ihtiyacım var.`, ipa: `pre-Sİ-zu dı a-JU-da`},{pt: `É uma emergência.`, tr: `Bu acil bir durum.`, ipa: `e U-ma e-mer-JEN-si-a`},{pt: `Chame a polícia, por favor.`, tr: `Lütfen polisi arayın.`, ipa: `ŞA-mi a po-Lİ-si-a, por fa-VOR`},{pt: `Preciso de um médico.`, tr: `Bir doktora ihtiyacım var.`, ipa: `pre-Sİ-zu dı um ME-ci-ku`},{pt: `Estou perdido.`, tr: `Kayboldum erkek.`, ipa: `iş-TOU per-Cİ-du`},{pt: `Onde fica a farmácia?`, tr: `Eczane nerede?`, ipa: `ON-ci Fİ-ka a far-MA-si-a`}], grammar: `Acil durumlarda tam cümle kurmak zorunda değilsin; “ajuda!”, “médico!”, “polícia!” bile anlaşılır. “Estou perdido/perdida” konuşmacının cinsiyetine göre değişir. “Preciso de...” kalıbı ihtiyaç belirtirken en güvenli yapıdır.`, practice: [`Yardıma ihtiyacın olduğunu söyle.`,`Eczanenin nerede olduğunu sor.`,`“Kayboldum” cümlesini kendi cinsiyetine göre kur.`,`Bir doktora ihtiyacın olduğunu söyle.`,`Acil durumda kullanacağın üç kelimeyi ezberle.`]},{day: 15, title: `Eczanede`, title_native: `Na farmácia`, focus: `Porto’da baş ağrısı, Rio’da güneş yanığı veya Luanda’da mide rahatsızlığı yaşarsan eczanede temel belirtileri anlatabilmelisin.`, vocab: [{pt: `remédio`, tr: `ilaç`, ipa: `he-ME-ci-u`},{pt: `dor de cabeça`, tr: `baş ağrısı`, ipa: `dor dı ka-BE-sa`},{pt: `febre`, tr: `ateş`, ipa: `FE-bri`},{pt: `tosse`, tr: `öksürük`, ipa: `TO-si`},{pt: `alergia`, tr: `alerji`, ipa: `a-ler-Jİ-a`},{pt: `estômago`, tr: `mide`, ipa: `iş-TO-ma-gu`},{pt: `protetor solar`, tr: `güneş kremi`, ipa: `pro-te-TOR so-LAR`},{pt: `receita`, tr: `reçete`, ipa: `he-SEY-ta`},{pt: `comprimido`, tr: `hap`, ipa: `kon-pri-Mİ-du`},{pt: `água`, tr: `su`, ipa: `A-gwa`}], phrases: [{pt: `Tenho dor de cabeça.`, tr: `Başım ağrıyor.`, ipa: `TEN-yu dor dı ka-BE-sa`},{pt: `Tenho alergia.`, tr: `Alerjim var.`, ipa: `TEN-yu a-ler-Jİ-a`},{pt: `Preciso de protetor solar.`, tr: `Güneş kremine ihtiyacım var.`, ipa: `pre-Sİ-zu dı pro-te-TOR so-LAR`},{pt: `Tem algo para tosse?`, tr: `Öksürük için bir şey var mı?`, ipa: `ten AL-gu PA-ra TO-si`},{pt: `Preciso de receita?`, tr: `Reçete gerekiyor mu?`, ipa: `pre-Sİ-zu dı he-SEY-ta`},{pt: `Como devo tomar?`, tr: `Nasıl almalıyım?`, ipa: `KO-mu DE-vu to-MAR`}], grammar: `“Tenho dor de...” vücuttaki ağrıları anlatmak için kullanılır: tenho dor de cabeça, tenho dor de estômago. “Para” burada “için” anlamındadır: algo para tosse. İlaç kullanırken mutlaka “como devo tomar?” diye sorabilirsin.`, practice: [`Başın ağrıdığını söyle.`,`Güneş kremine ihtiyacın olduğunu belirt.`,`Öksürük için bir şey iste.`,`Reçete gerekip gerekmediğini sor.`,`Bir ilacı nasıl alman gerektiğini sor.`]},{day: 16, title: `İnsanları ve şeyleri tarif etmek`, title_native: `Descrever pessoas e coisas`, focus: `Kaybolan bir çantayı, beğendiğin bir ürünü veya tanıştığın bir kişiyi tarif etmek için sıfatlara ihtiyacın olur.`, vocab: [{pt: `grande`, tr: `büyük`, ipa: `GRAN-ci`},{pt: `pequeno`, tr: `küçük`, ipa: `pe-KE-nu`},{pt: `bonito`, tr: `güzel erkek/nesne`, ipa: `bo-Nİ-tu`},{pt: `bonita`, tr: `güzel kadın/nesne`, ipa: `bo-Nİ-ta`},{pt: `novo`, tr: `yeni erkek/nesne`, ipa: `NO-vu`},{pt: `nova`, tr: `yeni kadın/nesne`, ipa: `NO-va`},{pt: `velho`, tr: `eski / yaşlı erkek`, ipa: `VE-lyu`},{pt: `velha`, tr: `eski / yaşlı kadın`, ipa: `VE-lya`},{pt: `preto`, tr: `siyah`, ipa: `PRE-tu`},{pt: `branco`, tr: `beyaz`, ipa: `BRAN-ku`}], phrases: [{pt: `É uma bolsa preta.`, tr: `Siyah bir çanta.`, ipa: `e U-ma BOL-sa PRE-ta`},{pt: `O quarto é pequeno.`, tr: `Oda küçük.`, ipa: `u KWAR-tu e pe-KE-nu`},{pt: `A cidade é bonita.`, tr: `Şehir güzel.`, ipa: `a si-DA-ci e bo-Nİ-ta`},{pt: `Meu telefone é novo.`, tr: `Telefonum yeni.`, ipa: `meu te-le-FO-ni e NO-vu`},{pt: `Procuro uma mala grande.`, tr: `Büyük bir valiz arıyorum.`, ipa: `pro-KU-ru U-ma MA-la GRAN-ci`},{pt: `Este lugar é muito bonito.`, tr: `Burası çok güzel.`, ipa: `EŞ-ti lu-GAR e MUY-tu bo-Nİ-tu`}], grammar: `Portekizcede sıfatlar çoğu zaman isimden sonra gelir ve cinsiyetle uyum sağlar: bolsa preta, quarto pequeno. “Cidade” dişil olduğu için “bonita” kullanılır. Seyahatte renk ve boyut sıfatları kayıp eşya veya alışverişte çok kullanılır.`, practice: [`Siyah bir çanta tarif et.`,`Odanın küçük olduğunu söyle.`,`Şehrin güzel olduğunu belirt.`,`Büyük bir valiz aradığını söyle.`,`Üç nesneyi renk ve boyutla tarif et.`]},{day: 17, title: `Aile ve arkadaşlar`, title_native: `Família e amigos`, focus: `Yerel biriyle sohbet ederken aile, arkadaşlar ve kiminle seyahat ettiğin hakkında konuşabilirsin.`, vocab: [{pt: `família`, tr: `aile`, ipa: `fa-Mİ-li-a`},{pt: `pai`, tr: `baba`, ipa: `pay`},{pt: `mãe`, tr: `anne`, ipa: `may`},{pt: `irmão`, tr: `erkek kardeş`, ipa: `ir-MAU`},{pt: `irmã`, tr: `kız kardeş`, ipa: `ir-MAN`},{pt: `filho`, tr: `oğul`, ipa: `Fİ-lyu`},{pt: `filha`, tr: `kız evlat`, ipa: `Fİ-lya`},{pt: `amigo`, tr: `erkek arkadaş`, ipa: `a-Mİ-gu`},{pt: `amiga`, tr: `kız arkadaş`, ipa: `a-Mİ-ga`},{pt: `sozinho`, tr: `yalnız erkek`, ipa: `so-ZİN-yu`}], phrases: [{pt: `Viajo com amigos.`, tr: `Arkadaşlarla seyahat ediyorum.`, ipa: `vi-A-ju kon a-Mİ-guş`},{pt: `Estou viajando sozinho.`, tr: `Yalnız seyahat ediyorum erkek.`, ipa: `iş-TOU vi-a-JAN-du so-ZİN-yu`},{pt: `Minha família está na Turquia.`, tr: `Ailem Türkiye’de.`, ipa: `MİN-ya fa-Mİ-li-a iş-TA na tur-Kİ-ya`},{pt: `Tenho uma irmã.`, tr: `Bir kız kardeşim var.`, ipa: `TEN-yu U-ma ir-MAN`},{pt: `Você tem filhos?`, tr: `Çocuğunuz var mı?`, ipa: `vo-SE ten Fİ-lyuş`},{pt: `Este é meu amigo.`, tr: `Bu benim arkadaşım.`, ipa: `EŞ-ti e meu a-Mİ-gu`}], grammar: `“Meu/minha” benim anlamındadır; isim erilse “meu”, dişilse “minha” kullanılır: meu amigo, minha família. “Tenho” sahiplik ve aile ilişkileri için kullanılır. “Sozinho/sozinha” konuşmacının cinsiyetine göre değişir.`, practice: [`Arkadaşlarla seyahat ettiğini söyle.`,`Ailenin Türkiye’de olduğunu belirt.`,`Bir kardeşin olduğunu Portekizce yaz.`,`Birine çocuğu olup olmadığını sor.`,`“Benim arkadaşım” ifadesini eril ve dişil şekilde kur.`]},{day: 18, title: `Sevme, isteme ve tercih etme`, title_native: `Gostar, querer e preferir`, focus: `Yemek, müzik, şehirler ve aktiviteler hakkında konuşurken beğenilerini açıklamak sosyal durumlarda çok işe yarar.`, vocab: [{pt: `gostar`, tr: `sevmek`, ipa: `goş-TAR`},{pt: `querer`, tr: `istemek`, ipa: `ke-RER`},{pt: `preferir`, tr: `tercih etmek`, ipa: `pre-fe-RİR`},{pt: `música`, tr: `müzik`, ipa: `MU-zi-ka`},{pt: `dançar`, tr: `dans etmek`, ipa: `dan-SAR`},{pt: `comer`, tr: `yemek yemek`, ipa: `ko-MER`},{pt: `beber`, tr: `içmek`, ipa: `be-BER`},{pt: `viajar`, tr: `seyahat etmek`, ipa: `vi-a-JAR`},{pt: `praia`, tr: `plaj`, ipa: `PRA-ya`},{pt: `museu`, tr: `müze`, ipa: `mu-ZEU`}], phrases: [{pt: `Eu gosto de música.`, tr: `Müzik severim.`, ipa: `eu GOŞ-tu dı MU-zi-ka`},{pt: `Gosto muito daqui.`, tr: `Burayı çok seviyorum.`, ipa: `GOŞ-tu MUY-tu da-Kİ`},{pt: `Prefiro café.`, tr: `Kahveyi tercih ederim.`, ipa: `pre-Fİ-ru ka-FE`},{pt: `Quero visitar o museu.`, tr: `Müzeyi ziyaret etmek istiyorum.`, ipa: `KE-ru vi-zi-TAR u mu-ZEU`},{pt: `Você gosta de dançar?`, tr: `Dans etmeyi sever misiniz?`, ipa: `vo-SE GOŞ-ta dı dan-SAR`},{pt: `Não gosto de peixe.`, tr: `Balık sevmem.`, ipa: `nau GOŞ-tu dı PEY-şi`}], grammar: `“Gostar” fiilinden sonra genellikle “de” gelir: gosto de café, gosto de música. “Quero + fiil” bir şey yapmak istediğini anlatır. “Prefiro” iki seçenek arasında tercih belirtirken kullanılır.`, practice: [`Müzik sevdiğini söyle.`,`Balık sevmediğini belirt.`,`Müzeyi ziyaret etmek istediğini söyle.`,`Birine dans etmeyi sevip sevmediğini sor.`,`Kahve ve çay arasında tercih cümlesi kur.`]},{day: 19, title: `Şehirde günlük işler`, title_native: `Tarefas na cidade`, focus: `Çamaşır yıkamak, para çekmek, telefon kartı almak veya markete gitmek gibi küçük işler uzun seyahatte önemlidir.`, vocab: [{pt: `banco`, tr: `banka`, ipa: `BAN-ku`},{pt: `caixa eletrônico`, tr: `ATM Brezilya`, ipa: `KAY-şa e-le-TRO-ni-ku`},{pt: `multibanco`, tr: `ATM Portekiz`, ipa: `mul-ti-BAN-ku`},{pt: `lavanderia`, tr: `çamaşırhane Brezilya`, ipa: `la-van-de-Rİ-a`},{pt: `lavandaria`, tr: `çamaşırhane Portekiz`, ipa: `la-van-da-Rİ-a`},{pt: `supermercado`, tr: `süpermarket`, ipa: `su-per-mer-KA-du`},{pt: `chip`, tr: `SIM kart / çip`, ipa: `şip`},{pt: `telefone`, tr: `telefon`, ipa: `te-le-FO-ni`},{pt: `internet`, tr: `internet`, ipa: `in-ter-NET`},{pt: `senha`, tr: `şifre`, ipa: `SEN-ya`}], phrases: [{pt: `Onde fica o banco?`, tr: `Banka nerede?`, ipa: `ON-ci Fİ-ka u BAN-ku`},{pt: `Preciso sacar dinheiro.`, tr: `Para çekmem gerekiyor.`, ipa: `pre-Sİ-zu sa-KAR ci-NYEY-ru`},{pt: `Quero comprar um chip.`, tr: `Bir SIM kart almak istiyorum.`, ipa: `KE-ru kon-PRAR um şip`},{pt: `Tem Wi-Fi aqui?`, tr: `Burada Wi-Fi var mı?`, ipa: `ten vay-FAY a-Kİ`},{pt: `Qual é a senha?`, tr: `Şifre nedir?`, ipa: `kwal e a SEN-ya`},{pt: `Onde posso lavar roupa?`, tr: `Nerede çamaşır yıkayabilirim?`, ipa: `ON-ci PO-su la-VAR HO-u-pa`}], grammar: `“Posso + fiil” bir şeyi yapıp yapamayacağını sormak için kullanılır: posso pagar, posso lavar, posso entrar. “Preciso + fiil” gereklilik anlatır. Portekiz ve Brezilya’da bazı günlük kelimeler farklı olabilir; bağlam genellikle anlaşmayı sağlar.`, practice: [`Bankanın nerede olduğunu sor.`,`Para çekmen gerektiğini söyle.`,`SIM kart almak istediğini belirt.`,`Wi-Fi şifresini sor.`,`Çamaşır yıkayabileceğin yeri sor.`]},{day: 20, title: `Telefon ve iletişim`, title_native: `Telefone e comunicação`, focus: `Yolda bağlantı kurmak, numara vermek, mesaj atmak veya arama yapmak gerekebilir.`, vocab: [{pt: `número`, tr: `numara`, ipa: `NU-me-ru`},{pt: `mensagem`, tr: `mesaj`, ipa: `men-SA-jen`},{pt: `ligar`, tr: `aramak`, ipa: `li-GAR`},{pt: `chamada`, tr: `arama`, ipa: `şa-MA-da`},{pt: `internet`, tr: `internet`, ipa: `in-ter-NET`},{pt: `carregador`, tr: `şarj cihazı`, ipa: `ka-he-ga-DOR`},{pt: `bateria`, tr: `batarya`, ipa: `ba-te-Rİ-a`},{pt: `telefone`, tr: `telefon`, ipa: `te-le-FO-ni`},{pt: `aplicativo`, tr: `uygulama Brezilya`, ipa: `a-pli-ka-Çİ-vu`},{pt: `aplicação`, tr: `uygulama Portekiz`, ipa: `a-pli-ka-SAU`}], phrases: [{pt: `Qual é o seu número?`, tr: `Numaranız nedir?`, ipa: `kwal e u seu NU-me-ru`},{pt: `Meu telefone não funciona.`, tr: `Telefonum çalışmıyor.`, ipa: `meu te-le-FO-ni nau fun-si-O-na`},{pt: `Preciso carregar o telefone.`, tr: `Telefonu şarj etmem gerekiyor.`, ipa: `pre-Sİ-zu ka-he-GAR u te-le-FO-ni`},{pt: `Posso ligar para você?`, tr: `Sizi arayabilir miyim?`, ipa: `PO-su li-GAR PA-ra vo-SE`},{pt: `Vou mandar uma mensagem.`, tr: `Mesaj göndereceğim.`, ipa: `vou man-DAR U-ma men-SA-jen`},{pt: `Tem carregador?`, tr: `Şarj cihazınız var mı?`, ipa: `ten ka-he-ga-DOR`}], grammar: `“Mandar uma mensagem” mesaj göndermek anlamına gelir. “Ligar para alguém” birini aramak demektir; “para” burada hedef kişiyi gösterir. “Não funciona” bozuk veya çalışmayan cihazlar için kullanılır.`, practice: [`Birinin numarasını sor.`,`Telefonunun çalışmadığını söyle.`,`Telefonu şarj etmen gerektiğini belirt.`,`Mesaj göndereceğini söyle.`,`Şarj cihazı olup olmadığını sor.`]},{day: 21, title: `Geçmişten bahsetme`, title_native: `Falar do passado`, focus: `Dün nereye gittiğini, ne yediğini veya ne gördüğünü anlatmak gezgin sohbetlerinde çok yaygındır.`, vocab: [{pt: `fui`, tr: `gittim / oldum`, ipa: `fuy`},{pt: `vi`, tr: `gördüm`, ipa: `vi`},{pt: `comi`, tr: `yedim`, ipa: `ko-Mİ`},{pt: `bebi`, tr: `içtim`, ipa: `be-Bİ`},{pt: `ontem`, tr: `dün`, ipa: `ON-ten`},{pt: `cidade`, tr: `şehir`, ipa: `si-DA-ci`},{pt: `museu`, tr: `müze`, ipa: `mu-ZEU`},{pt: `restaurante`, tr: `restoran`, ipa: `heş-tau-RAN-çi`},{pt: `praia`, tr: `plaj`, ipa: `PRA-ya`},{pt: `passeio`, tr: `gezi`, ipa: `pa-SEY-u`}], phrases: [{pt: `Ontem fui ao museu.`, tr: `Dün müzeye gittim.`, ipa: `ON-ten fuy au mu-ZEU`},{pt: `Comi peixe no restaurante.`, tr: `Restoranda balık yedim.`, ipa: `ko-Mİ PEY-şi nu heş-tau-RAN-çi`},{pt: `Vi uma praça bonita.`, tr: `Güzel bir meydan gördüm.`, ipa: `vi U-ma PRA-sa bo-Nİ-ta`},{pt: `Bebi café de manhã.`, tr: `Sabah kahve içtim.`, ipa: `be-Bİ ka-FE dı ma-NYAN`},{pt: `Gostei muito.`, tr: `Çok beğendim.`, ipa: `goş-TEY MUY-tu`},{pt: `Não gostei muito.`, tr: `Çok beğenmedim.`, ipa: `nau goş-TEY MUY-tu`}], grammar: `Bugün düzenli geçmiş zamanı ayrıntılı öğrenmek yerine en sık kullanılan kısa formlara odaklanıyorsun: fui, vi, comi, bebi. “Gostei” “beğendim” demektir ve seyahatte deneyim anlatmak için çok kullanılır. “Ontem” cümlenin başında veya sonunda kullanılabilir.`, practice: [`Dün müzeye gittiğini söyle.`,`Restoranda ne yediğini hayal ederek cümle kur.`,`Güzel bir meydan gördüğünü söyle.`,`Bir şeyi beğendiğini ve beğenmediğini ifade et.`,`Dünkü günün hakkında üç kısa Portekizce cümle yaz.`]},{day: 22, title: `Gelecek planları`, title_native: `Planos futuros`, focus: `Tur rezervasyonu yaparken, arkadaşla buluşurken veya yarınki geziyi anlatırken gelecek zamanı basitçe kurabilirsin.`, vocab: [{pt: `vou`, tr: `gideceğim / yapacağım`, ipa: `vou`},{pt: `visitar`, tr: `ziyaret etmek`, ipa: `vi-zi-TAR`},{pt: `comprar`, tr: `satın almak`, ipa: `kon-PRAR`},{pt: `ficar`, tr: `kalmak`, ipa: `fi-KAR`},{pt: `encontrar`, tr: `buluşmak`, ipa: `en-kon-TRAR`},{pt: `sair`, tr: `çıkmak`, ipa: `sa-İR`},{pt: `chegar`, tr: `varmak`, ipa: `şe-GAR`},{pt: `partir`, tr: `ayrılmak`, ipa: `par-ÇİR`},{pt: `amanhã`, tr: `yarın`, ipa: `a-ma-NYAN`},{pt: `depois`, tr: `sonra`, ipa: `de-POYŞ`}], phrases: [{pt: `Amanhã vou visitar Belém.`, tr: `Yarın Belém’i ziyaret edeceğim.`, ipa: `a-ma-NYAN vou vi-zi-TAR be-LEN`},{pt: `Vou comprar lembranças.`, tr: `Hediyelik eşya alacağım.`, ipa: `vou kon-PRAR len-BRAN-saş`},{pt: `Vou ficar três noites.`, tr: `Üç gece kalacağım.`, ipa: `vou fi-KAR treyş NOY-çiş`},{pt: `Vamos sair à noite.`, tr: `Gece dışarı çıkacağız.`, ipa: `VA-muş sa-İR a NOY-çi`},{pt: `Que horas você vai chegar?`, tr: `Saat kaçta varacaksınız?`, ipa: `ki O-raş vo-SE vay şe-GAR`},{pt: `Depois vou descansar.`, tr: `Sonra dinleneceğim.`, ipa: `de-POYŞ vou deş-kan-SAR`}], grammar: `“Vou + fiil” çok kolay ve çok kullanılan gelecek yapısıdır. “Vamos + fiil” “biz ... yapacağız” anlamına gelir. Turistik planlarda bu yapı, karmaşık gelecek zaman çekimlerinden daha pratiktir.`, practice: [`Yarın bir yeri ziyaret edeceğini söyle.`,`Üç gece kalacağını belirt.`,`Gece dışarı çıkacağınızı söyle.`,`Birine saat kaçta varacağını sor.`,`“Vou” ile üç farklı gelecek planı yaz.`]},{day: 23, title: `Sorular sorma`, title_native: `Fazer perguntas`, focus: `Bilmediğin bir şehirde doğru soruları sorabilmek, kelime eksiklerini bile telafi eder.`, vocab: [{pt: `quem`, tr: `kim`, ipa: `keyn`},{pt: `o que`, tr: `ne`, ipa: `u ki`},{pt: `onde`, tr: `nerede`, ipa: `ON-ci`},{pt: `quando`, tr: `ne zaman`, ipa: `KWAN-du`},{pt: `quanto`, tr: `ne kadar`, ipa: `KWAN-tu`},{pt: `como`, tr: `nasıl`, ipa: `KO-mu`},{pt: `por quê`, tr: `neden`, ipa: `por KE`},{pt: `qual`, tr: `hangi / ne`, ipa: `kwal`},{pt: `entrada`, tr: `giriş`, ipa: `en-TRA-da`},{pt: `saída`, tr: `çıkış`, ipa: `sa-İ-da`}], phrases: [{pt: `Onde fica a saída?`, tr: `Çıkış nerede?`, ipa: `ON-ci Fİ-ka a sa-İ-da`},{pt: `Quando abre?`, tr: `Ne zaman açılır?`, ipa: `KWAN-du A-bri`},{pt: `Quanto custa a entrada?`, tr: `Giriş ücreti ne kadar?`, ipa: `KWAN-tu KUŞ-ta a en-TRA-da`},{pt: `Como chego ao centro?`, tr: `Merkeze nasıl giderim?`, ipa: `KO-mu ŞE-gu au SEN-tru`},{pt: `Qual é melhor?`, tr: `Hangisi daha iyi?`, ipa: `kwal e me-LYOR`},{pt: `Por que está fechado?`, tr: `Neden kapalı?`, ipa: `por KE iş-TA fe-ŞA-du`}], grammar: `Soru kelimeleri cümlenin başında kullanılır ve tonlama önemlidir. “Qual” bazen “hangi”, bazen “ne” anlamına gelir; seçenekler arasında sormak için çok uygundur. “Como chego a...” bir yere nasıl gideceğini sormak için doğal bir kalıptır.`, practice: [`Çıkışın nerede olduğunu sor.`,`Giriş ücretini sor.`,`Merkeze nasıl gideceğini sor.`,`Hangisinin daha iyi olduğunu sor.`,`Bugünkü soru kelimeleriyle beş mini soru yaz.`]},{day: 24, title: `Anlamadığında ne söylemeli`, title_native: `Quando não entende`, focus: `Hızlı konuşulan Portekizce karşısında panik yapmadan açıklama, tekrar ve yavaş konuşma isteyebilirsin.`, vocab: [{pt: `entender`, tr: `anlamak`, ipa: `en-ten-DER`},{pt: `falar`, tr: `konuşmak`, ipa: `fa-LAR`},{pt: `devagar`, tr: `yavaş`, ipa: `de-va-GAR`},{pt: `repetir`, tr: `tekrar etmek`, ipa: `he-pe-ÇİR`},{pt: `escrever`, tr: `yazmak`, ipa: `iş-kre-VER`},{pt: `português`, tr: `Portekizce`, ipa: `por-tu-GEŞ`},{pt: `turco`, tr: `Türkçe`, ipa: `TUR-ku`},{pt: `inglês`, tr: `İngilizce`, ipa: `in-GLEŞ`},{pt: `palavra`, tr: `kelime`, ipa: `pa-LA-vra`},{pt: `frase`, tr: `cümle`, ipa: `FRA-zi`}], phrases: [{pt: `Não entendo.`, tr: `Anlamıyorum.`, ipa: `nau en-TEN-du`},{pt: `Entendo um pouco.`, tr: `Biraz anlıyorum.`, ipa: `en-TEN-du um POU-ku`},{pt: `Fale mais devagar, por favor.`, tr: `Lütfen daha yavaş konuşun.`, ipa: `FA-li mayş de-va-GAR, por fa-VOR`},{pt: `Pode repetir, por favor?`, tr: `Lütfen tekrar eder misiniz?`, ipa: `PO-ci he-pe-ÇİR, por fa-VOR`},{pt: `Pode escrever?`, tr: `Yazabilir misiniz?`, ipa: `PO-ci iş-kre-VER`},{pt: `Você fala inglês?`, tr: `İngilizce konuşuyor musunuz?`, ipa: `vo-SE FA-la in-GLEŞ`}], grammar: `“Não entendo” kısa ve çok kullanışlıdır. “Um pouco” biraz anlamına gelir; dil seviyeni anlatırken “falo um pouco de português” diyebilirsin. “Pode + fiil?” kibar istek sormanın en güvenli yollarından biridir.`, practice: [`Anlamadığını söyle.`,`Biraz anladığını belirt.`,`Daha yavaş konuşmasını iste.`,`Yazmasını rica et.`,`İngilizce konuşup konuşmadığını sor.`]},{day: 25, title: `Yerel insanlarla küçük sohbet`, title_native: `Conversa informal com locais`, focus: `Bir kafede, turda veya hostelde yerel biriyle kısa ve samimi sohbet kurmak seyahati daha keyifli hale getirir.`, vocab: [{pt: `legal`, tr: `güzel / havalı Brezilya`, ipa: `le-GAU`},{pt: `fixe`, tr: `güzel / havalı Portekiz`, ipa: `Fİ-şi`},{pt: `cidade`, tr: `şehir`, ipa: `si-DA-ci`},{pt: `bairro`, tr: `semt`, ipa: `BAY-hu`},{pt: `trabalho`, tr: `iş`, ipa: `tra-BA-lyu`},{pt: `viagem`, tr: `seyahat`, ipa: `vi-A-jen`},{pt: `cultura`, tr: `kültür`, ipa: `kul-TU-ra`},{pt: `comida`, tr: `yemek`, ipa: `ko-Mİ-da`},{pt: `música`, tr: `müzik`, ipa: `MU-zi-ka`},{pt: `história`, tr: `tarih / hikâye`, ipa: `iş-TO-ri-a`}], phrases: [{pt: `Esta cidade é muito bonita.`, tr: `Bu şehir çok güzel.`, ipa: `EŞ-ta si-DA-ci e MUY-tu bo-Nİ-ta`},{pt: `Você mora aqui?`, tr: `Burada mı yaşıyorsunuz?`, ipa: `vo-SE MO-ra a-Kİ`},{pt: `É minha primeira vez aqui.`, tr: `Burada ilk kez bulunuyorum.`, ipa: `e MİN-ya pri-MEY-ra veş a-Kİ`},{pt: `Gosto muito da comida.`, tr: `Yemeği çok seviyorum.`, ipa: `GOŞ-tu MUY-tu da ko-Mİ-da`},{pt: `O que devo visitar?`, tr: `Nereyi ziyaret etmeliyim?`, ipa: `u ki DE-vu vi-zi-TAR`},{pt: `Obrigado pela dica.`, tr: `Tavsiye için teşekkür ederim.`, ipa: `ob-ri-GA-du PE-la Dİ-ka`}], grammar: `“Dica” tavsiye veya ipucu demektir ve yerel öneriler için sık kullanılır. “Devo + fiil” “... yapmalı mıyım / yapmalıyım” anlamında kullanılır. Küçük sohbetlerde iltifat etmek ve öneri sormak doğal bir başlangıçtır.`, practice: [`Şehri beğendiğini söyle.`,`Birine burada yaşayıp yaşamadığını sor.`,`İlk kez burada olduğunu belirt.`,`Yerel öneri iste.`,`Tavsiye için teşekkür et.`]},{day: 26, title: `Konaklama sorunları`, title_native: `Problemas na hospedagem`, focus: `Otelde veya kiralık evde klima, internet, sıcak su ya da temizlik gibi sorunları nazikçe bildirebilmelisin.`, vocab: [{pt: `problema`, tr: `sorun`, ipa: `pro-BLE-ma`},{pt: `quarto`, tr: `oda`, ipa: `KWAR-tu`},{pt: `ar-condicionado`, tr: `klima`, ipa: `ar kon-di-si-o-NA-du`},{pt: `internet`, tr: `internet`, ipa: `in-ter-NET`},{pt: `chuveiro`, tr: `duş`, ipa: `şu-VEY-ru`},{pt: `água quente`, tr: `sıcak su`, ipa: `A-gwa KEN-çi`},{pt: `limpo`, tr: `temiz erkek/nesne`, ipa: `LİN-pu`},{pt: `sujo`, tr: `kirli erkek/nesne`, ipa: `SU-ju`},{pt: `barulho`, tr: `gürültü`, ipa: `ba-RU-lyu`},{pt: `toalha`, tr: `havlu`, ipa: `to-A-lya`}], phrases: [{pt: `Há um problema no quarto.`, tr: `Odada bir sorun var.`, ipa: `a um pro-BLE-ma nu KWAR-tu`},{pt: `O ar-condicionado não funciona.`, tr: `Klima çalışmıyor.`, ipa: `u ar kon-di-si-o-NA-du nau fun-si-O-na`},{pt: `Não há água quente.`, tr: `Sıcak su yok.`, ipa: `nau a A-gwa KEN-çi`},{pt: `Preciso de toalhas limpas.`, tr: `Temiz havlulara ihtiyacım var.`, ipa: `pre-Sİ-zu dı to-A-lyaş LİN-paş`},{pt: `O quarto está sujo.`, tr: `Oda kirli.`, ipa: `u KWAR-tu iş-TA SU-ju`},{pt: `Tem muito barulho.`, tr: `Çok gürültü var.`, ipa: `ten MUY-tu ba-RU-lyu`}], grammar: `“Há” ve “tem” ikisi de “var” anlamında duyulabilir; Brezilya’da konuşma dilinde “tem” çok yaygındır. Sorun bildirirken “há um problema...” veya “tem um problema...” ile başlamak kibar ve nettir. “Não funciona” cihaz sorunları için en kolay kalıptır.`, practice: [`Odada sorun olduğunu söyle.`,`Klimanın çalışmadığını bildir.`,`Sıcak su olmadığını söyle.`,`Temiz havlu iste.`,`Çok gürültü olduğunu belirt.`]},{day: 27, title: `Rezervasyon yapmak`, title_native: `Fazer uma reserva`, focus: `Popüler restoranlar, turlar ve müzeler için rezervasyon veya randevu oluşturman gerekebilir.`, vocab: [{pt: `reserva`, tr: `rezervasyon`, ipa: `he-ZER-va`},{pt: `mesa`, tr: `masa`, ipa: `ME-za`},{pt: `pessoa`, tr: `kişi`, ipa: `pe-SO-a`},{pt: `horário`, tr: `saat / zaman dilimi`, ipa: `o-RA-ri-u`},{pt: `disponível`, tr: `müsait`, ipa: `dis-po-Nİ-vel`},{pt: `confirmar`, tr: `onaylamak`, ipa: `kon-fir-MAR`},{pt: `cancelar`, tr: `iptal etmek`, ipa: `kan-se-LAR`},{pt: `nome`, tr: `isim`, ipa: `NO-mi`},{pt: `telefone`, tr: `telefon`, ipa: `te-le-FO-ni`},{pt: `entrada`, tr: `giriş`, ipa: `en-TRA-da`}], phrases: [{pt: `Queria fazer uma reserva.`, tr: `Rezervasyon yapmak isterdim.`, ipa: `ke-Rİ-a fa-ZER U-ma he-ZER-va`},{pt: `Para duas pessoas.`, tr: `İki kişi için.`, ipa: `PA-ra DU-aş pe-SO-aş`},{pt: `Tem horário disponível às oito?`, tr: `Saat sekizde müsaitlik var mı?`, ipa: `ten o-RA-ri-u dis-po-Nİ-vel aş OY-tu`},{pt: `Em nome de Deniz.`, tr: `Deniz adına.`, ipa: `en NO-mi dı de-NİZ`},{pt: `Posso confirmar por mensagem?`, tr: `Mesajla onaylayabilir miyim?`, ipa: `PO-su kon-fir-MAR por men-SA-jen`},{pt: `Preciso cancelar a reserva.`, tr: `Rezervasyonu iptal etmem gerekiyor.`, ipa: `pre-Sİ-zu kan-se-LAR a he-ZER-va`}], grammar: `“Para duas pessoas” restoran ve tur rezervasyonlarında kişi sayısı belirtmek için kullanılır. “Em nome de...” rezervasyonun hangi isimle yapılacağını söyler. Saatlerde “às oito” gibi “às” kullanımı belirli saati işaret eder.`, practice: [`Rezervasyon yapmak istediğini söyle.`,`İki kişi için masa iste.`,`Saat sekizde müsaitlik sor.`,`Kendi adın adına rezervasyon cümlesi kur.`,`Rezervasyonu iptal etmen gerektiğini söyle.`]},{day: 28, title: `Kültürel nezaket ve davetler`, title_native: `Cortesia e convites`, focus: `Yerel biri seni bir etkinliğe, yemeğe veya gezmeye davet ederse nazikçe kabul etmeyi ya da reddetmeyi bilmelisin.`, vocab: [{pt: `convite`, tr: `davet`, ipa: `kon-Vİ-çi`},{pt: `festa`, tr: `parti`, ipa: `FEŞ-ta`},{pt: `jantar`, tr: `akşam yemeği`, ipa: `jan-TAR`},{pt: `almoço`, tr: `öğle yemeği`, ipa: `al-MO-su`},{pt: `aceitar`, tr: `kabul etmek`, ipa: `a-sey-TAR`},{pt: `recusar`, tr: `reddetmek`, ipa: `he-ku-ZAR`},{pt: `talvez`, tr: `belki`, ipa: `tal-VEŞ`},{pt: `claro`, tr: `tabii`, ipa: `KLA-ru`},{pt: `desculpa`, tr: `özür`, ipa: `deş-KUL-pa`},{pt: `gentil`, tr: `nazik`, ipa: `jen-ÇİL`}], phrases: [{pt: `Obrigado pelo convite.`, tr: `Davet için teşekkür ederim.`, ipa: `ob-ri-GA-du PE-lu kon-Vİ-çi`},{pt: `Claro, adoraria.`, tr: `Tabii, çok isterim.`, ipa: `KLA-ru, a-do-ra-Rİ-a`},{pt: `Talvez mais tarde.`, tr: `Belki daha sonra.`, ipa: `tal-VEŞ mayş TAR-ci`},{pt: `Desculpa, não posso.`, tr: `Üzgünüm, gelemem / yapamam.`, ipa: `deş-KUL-pa, nau PO-su`},{pt: `Foi muito gentil.`, tr: `Çok nazikti.`, ipa: `foy MUY-tu jen-ÇİL`},{pt: `Podemos combinar amanhã?`, tr: `Yarın ayarlayabilir miyiz?`, ipa: `po-DE-muş kon-bi-NAR a-ma-NYAN`}], grammar: `“Adoraria” çok isterdim anlamında sıcak ve kibar bir kabul ifadesidir. “Não posso” doğrudan “yapamam / gelemem” demektir; başına “desculpa” eklemek yumuşatır. Davetlerde teşekkür etmek Portekizce konuşulan kültürlerde önemlidir.`, practice: [`Davet için teşekkür et.`,`Daveti kabul eden sıcak bir cümle kur.`,`Nazikçe reddet.`,`Yarın ayarlamayı öner.`,`“Belki daha sonra” ifadesini sosyal bir bağlamda kullan.`]},{day: 29, title: `Sınırda ve havaalanında`, title_native: `No aeroporto e na fronteira`, focus: `Portekiz, Brezilya veya başka bir Portekizce konuşulan ülkeye girişte pasaport kontrolü ve bagaj işlemleri için temel ifadeler gerekir.`, vocab: [{pt: `aeroporto`, tr: `havaalanı`, ipa: `a-e-ro-POR-tu`},{pt: `passaporte`, tr: `pasaport`, ipa: `pa-sa-POR-çi`},{pt: `bagagem`, tr: `bagaj`, ipa: `ba-GA-jen`},{pt: `mala`, tr: `valiz`, ipa: `MA-la`},{pt: `voo`, tr: `uçuş`, ipa: `vo-u`},{pt: `portão`, tr: `kapı`, ipa: `por-TAU`},{pt: `embarque`, tr: `biniş`, ipa: `en-BAR-ki`},{pt: `chegada`, tr: `varış`, ipa: `şe-GA-da`},{pt: `partida`, tr: `kalkış`, ipa: `par-Çİ-da`},{pt: `alfândega`, tr: `gümrük`, ipa: `al-FAN-de-ga`}], phrases: [{pt: `Aqui está meu passaporte.`, tr: `Pasaportum burada.`, ipa: `a-Kİ iş-TA meu pa-sa-POR-çi`},{pt: `Estou aqui de férias.`, tr: `Tatil için buradayım.`, ipa: `iş-TOU a-Kİ dı FE-ri-aş`},{pt: `Vou ficar dez dias.`, tr: `On gün kalacağım.`, ipa: `vou fi-KAR deş Dİ-aş`},{pt: `Onde pego a bagagem?`, tr: `Bagajı nereden alırım?`, ipa: `ON-ci PE-gu a ba-GA-jen`},{pt: `Meu voo está atrasado.`, tr: `Uçuşum gecikmiş.`, ipa: `meu vo-u iş-TA a-tra-ZA-du`},{pt: `Qual é o portão?`, tr: `Kapı hangisi?`, ipa: `kwal e u por-TAU`}], grammar: `Pasaport kontrolünde kısa ve net cevaplar en iyisidir. “Estou aqui de férias” tatil için geldiğini anlatır. “Vou ficar...” kalıbı kalış süresini belirtmek için kullanılır ve sınır görevlileriyle konuşurken çok pratiktir.`, practice: [`Tatil için burada olduğunu söyle.`,`On gün kalacağını belirt.`,`Bagajı nereden alacağını sor.`,`Uçuşunun geciktiğini söyle.`,`Kapı numarasını sormayı çalış.`]},{day: 30, title: `Seyahat günü konuşması`, title_native: `Conversa de viagem`, focus: `Artık selamlaşma, sipariş, yön, ulaşım, otel, sorun ve sohbet kalıplarını birleştiriyorsun. Bugün gerçek bir seyahat gününü baştan sona Portekizce yönetmeyi deneyeceksin.`, vocab: [{pt: `viagem`, tr: `seyahat`, ipa: `vi-A-jen`},{pt: `destino`, tr: `varış yeri`, ipa: `deş-Tİ-nu`},{pt: `centro`, tr: `merkez`, ipa: `SEN-tru`},{pt: `reserva`, tr: `rezervasyon`, ipa: `he-ZER-va`},{pt: `bilhete`, tr: `bilet`, ipa: `bi-LYE-ti`},{pt: `comida`, tr: `yemek`, ipa: `ko-Mİ-da`},{pt: `ajuda`, tr: `yardım`, ipa: `a-JU-da`},{pt: `mapa`, tr: `harita`, ipa: `MA-pa`},{pt: `dinheiro`, tr: `para`, ipa: `ci-NYEY-ru`},{pt: `lembrança`, tr: `hediyelik eşya`, ipa: `len-BRAN-sa`}], phrases: [{pt: `Hoje vou ao centro.`, tr: `Bugün merkeze gideceğim.`, ipa: `O-ji vou au SEN-tru`},{pt: `Tenho uma reserva no hotel.`, tr: `Otelde rezervasyonum var.`, ipa: `TEN-yu U-ma he-ZER-va nu o-TEL`},{pt: `Preciso comprar um bilhete.`, tr: `Bilet almam gerekiyor.`, ipa: `pre-Sİ-zu kon-PRAR um bi-LYE-ti`},{pt: `Onde posso comer bem?`, tr: `Nerede iyi yemek yiyebilirim?`, ipa: `ON-ci PO-su ko-MER bayn`},{pt: `Pode me ajudar?`, tr: `Bana yardım edebilir misiniz?`, ipa: `PO-ci mi a-ju-DAR`},{pt: `Foi um dia ótimo.`, tr: `Harika bir gündü.`, ipa: `foy um Dİ-a O-çi-mu`}], grammar: `Bugün farklı yapıları bir araya getiriyorsun: “tenho” sahiplik, “vou” gelecek, “preciso” gereklilik, “posso” izin/yetenek, “onde” yer sorusu için. Gerçek hayatta akıcılık, mükemmel gramerden daha önemlidir. Kısa, nazik ve net cümleler seyahatte yeterince güçlüdür.`, practice: [`Bugün merkeze gideceğini söyle.`,`Otel rezervasyonun olduğunu belirt.`,`Bilet alman gerektiğini söyle.`,`İyi yemek yenebilecek bir yer sor.`,`Tüm kurstan öğrendiğin ifadelerle beş cümlelik bir seyahat günü anlat.`]}];

var CONVERSATIONS_TR_PT = [{id: 1, title: `Lizbon’da kafede sipariş`, scene: `Lizbon’da küçük bir kafeye giriyorsun. Pastel de nata ve kahve almak istiyorsun, ama önce burada mı yoksa paket mi olduğunu söylüyorsun.`, lines: [{who: `them`, pt: `Bom dia, o que deseja?`, tr: `Günaydın, ne istersiniz?`},{who: `you`, pt: `Bom dia, queria um café com leite, por favor.`, tr: `Günaydın, sütlü bir kahve isterdim, lütfen.`},{who: `them`, pt: `Claro, mais alguma coisa?`, tr: `Tabii, başka bir şey?`},{who: `you`, pt: `Sim, um pastel de nata também.`, tr: `Evet, bir pastel de nata da.`},{who: `them`, pt: `Para aqui ou para levar?`, tr: `Burada mı, paket mi?`},{who: `you`, pt: `Para aqui, por favor.`, tr: `Burada, lütfen.`},{who: `them`, pt: `Com açúcar no café?`, tr: `Kahveye şeker ister misiniz?`},{who: `you`, pt: `Sem açúcar, obrigado.`, tr: `Şekersiz, teşekkür ederim.`},{who: `them`, pt: `São quatro euros.`, tr: `Dört avro.`},{who: `you`, pt: `Posso pagar com cartão?`, tr: `Kartla ödeyebilir miyim?`},{who: `them`, pt: `Sim, claro.`, tr: `Evet, tabii.`},{who: `you`, pt: `Obrigado, bom dia.`, tr: `Teşekkür ederim, iyi günler.`}]},{id: 2, title: `Otelde check-in`, scene: `Porto’da oteline vardın ve resepsiyona yaklaşıyorsun. Rezervasyonunu, pasaportunu ve kahvaltı bilgisini konuşuyorsun.`, lines: [{who: `them`, pt: `Boa tarde, bem-vindo ao hotel.`, tr: `İyi öğleden sonra, otele hoş geldiniz.`},{who: `you`, pt: `Boa tarde, tenho uma reserva.`, tr: `İyi öğleden sonra, rezervasyonum var.`},{who: `them`, pt: `Qual é o seu nome?`, tr: `Adınız nedir?`},{who: `you`, pt: `Meu nome é Deniz Kaya.`, tr: `Benim adım Deniz Kaya.`},{who: `them`, pt: `Pode mostrar o passaporte, por favor?`, tr: `Pasaportunuzu gösterebilir misiniz, lütfen?`},{who: `you`, pt: `Claro, aqui está meu passaporte.`, tr: `Tabii, pasaportum burada.`},{who: `them`, pt: `Sua reserva é por três noites.`, tr: `Rezervasyonunuz üç gece için.`},{who: `you`, pt: `O café da manhã está incluído?`, tr: `Kahvaltı dahil mi?`},{who: `them`, pt: `Sim, das sete às dez.`, tr: `Evet, yediden ona kadar.`},{who: `you`, pt: `Qual é o número do quarto?`, tr: `Oda numarası kaç?`},{who: `them`, pt: `É o quarto duzentos e cinco.`, tr: `İki yüz beş numaralı oda.`},{who: `you`, pt: `Obrigado pela ajuda.`, tr: `Yardımınız için teşekkür ederim.`}]},{id: 3, title: `Yol tarifi isteme`, scene: `Alfama’da yürürken metro istasyonunu bulamıyorsun. Sokaktaki birine nazikçe yaklaşıp haritada göstermesini istiyorsun.`, lines: [{who: `you`, pt: `Desculpe, pode me ajudar?`, tr: `Affedersiniz, bana yardım edebilir misiniz?`},{who: `them`, pt: `Claro, diga.`, tr: `Tabii, söyleyin.`},{who: `you`, pt: `Onde fica a estação de metrô?`, tr: `Metro istasyonu nerede?`},{who: `them`, pt: `Fica perto daqui.`, tr: `Buraya yakın.`},{who: `you`, pt: `Posso ir a pé?`, tr: `Yürüyerek gidebilir miyim?`},{who: `them`, pt: `Sim, siga em frente e vire à direita.`, tr: `Evet, düz gidin ve sağa dönün.`},{who: `you`, pt: `Depois viro à esquerda?`, tr: `Sonra sola mı dönüyorum?`},{who: `them`, pt: `Não, continue em frente até a praça.`, tr: `Hayır, meydana kadar düz devam edin.`},{who: `you`, pt: `Pode mostrar no mapa?`, tr: `Haritada gösterebilir misiniz?`},{who: `them`, pt: `Sim, é aqui.`, tr: `Evet, burada.`},{who: `you`, pt: `Muito obrigado.`, tr: `Çok teşekkür ederim.`},{who: `them`, pt: `De nada, boa viagem.`, tr: `Rica ederim, iyi yolculuklar.`}]},{id: 4, title: `Restoranda akşam yemeği`, scene: `Rio de Janeiro’da bir restorandasın. Menüden emin değilsin, garsona öneri soruyor ve et yemediğini söylüyorsun.`, lines: [{who: `them`, pt: `Boa noite, já escolheu?`, tr: `İyi akşamlar, seçtiniz mi?`},{who: `you`, pt: `Ainda não, posso ver o menu?`, tr: `Henüz hayır, menüyü görebilir miyim?`},{who: `them`, pt: `Claro, aqui está.`, tr: `Tabii, işte burada.`},{who: `you`, pt: `O que recomenda?`, tr: `Ne önerirsiniz?`},{who: `them`, pt: `O peixe com arroz é muito bom.`, tr: `Pirinçli balık çok iyidir.`},{who: `you`, pt: `Ótimo, não como carne.`, tr: `Harika, et yemiyorum.`},{who: `them`, pt: `Então o peixe é uma boa opção.`, tr: `O zaman balık iyi bir seçenek.`},{who: `you`, pt: `Queria esse prato, por favor.`, tr: `Bu yemeği isterdim, lütfen.`},{who: `them`, pt: `Quer alguma bebida?`, tr: `İçecek ister misiniz?`},{who: `you`, pt: `Uma água sem gás, por favor.`, tr: `Gazsız bir su, lütfen.`},{who: `them`, pt: `Perfeito, já trago.`, tr: `Tamam, hemen getiriyorum.`},{who: `you`, pt: `Obrigado.`, tr: `Teşekkür ederim.`}]},{id: 5, title: `Bilet almak`, scene: `Porto’da tren istasyonundasın ve Braga’ya gitmek istiyorsun. Gidiş dönüş bilet, saat ve peron bilgisi soruyorsun.`, lines: [{who: `them`, pt: `Bom dia, próximo.`, tr: `Günaydın, sıradaki.`},{who: `you`, pt: `Bom dia, um bilhete para Braga, por favor.`, tr: `Günaydın, Braga’ya bir bilet, lütfen.`},{who: `them`, pt: `Só ida ou ida e volta?`, tr: `Sadece gidiş mi, gidiş dönüş mü?`},{who: `you`, pt: `Ida e volta, por favor.`, tr: `Gidiş dönüş, lütfen.`},{who: `them`, pt: `Para hoje?`, tr: `Bugün için mi?`},{who: `you`, pt: `Sim, para hoje.`, tr: `Evet, bugün için.`},{who: `them`, pt: `O próximo comboio sai às onze.`, tr: `Bir sonraki tren saat on birde kalkıyor.`},{who: `you`, pt: `Quanto tempo demora?`, tr: `Ne kadar sürer?`},{who: `them`, pt: `Cerca de uma hora.`, tr: `Yaklaşık bir saat.`},{who: `you`, pt: `Qual é o portão?`, tr: `Kapı hangisi?`},{who: `them`, pt: `Portão três.`, tr: `Üç numaralı kapı.`},{who: `you`, pt: `Obrigado, bom dia.`, tr: `Teşekkür ederim, iyi günler.`}]},{id: 6, title: `Pazarda alışveriş`, scene: `Salvador’da renkli bir pazardasın. Hediyelik eşya bakıyor, fiyat soruyor ve kartla ödeme yapıp yapamayacağını öğreniyorsun.`, lines: [{who: `them`, pt: `Olá, posso ajudar?`, tr: `Merhaba, yardımcı olabilir miyim?`},{who: `you`, pt: `Olá, estou só olhando.`, tr: `Merhaba, sadece bakıyorum.`},{who: `them`, pt: `Claro, fique à vontade.`, tr: `Tabii, rahatça bakın.`},{who: `you`, pt: `Quanto custa isto?`, tr: `Bu ne kadar?`},{who: `them`, pt: `Custa vinte reais.`, tr: `Yirmi real.`},{who: `you`, pt: `Tem em outra cor?`, tr: `Başka rengi var mı?`},{who: `them`, pt: `Sim, temos azul e branco.`, tr: `Evet, mavi ve beyaz var.`},{who: `you`, pt: `Vou levar o branco.`, tr: `Beyaz olanı alacağım.`},{who: `them`, pt: `Perfeito. Precisa de sacola?`, tr: `Harika. Poşet ister misiniz?`},{who: `you`, pt: `Sim, por favor. Posso pagar com cartão?`, tr: `Evet, lütfen. Kartla ödeyebilir miyim?`},{who: `them`, pt: `Pode sim.`, tr: `Evet, ödeyebilirsiniz.`},{who: `you`, pt: `Obrigado pela ajuda.`, tr: `Yardımınız için teşekkür ederim.`}]},{id: 7, title: `Eczanede yardım isteme`, scene: `Lizbon’da baş ağrın var ve en yakın eczaneye giriyorsun. Belirtini anlatıp ilacı nasıl kullanacağını soruyorsun.`, lines: [{who: `them`, pt: `Boa tarde, precisa de ajuda?`, tr: `İyi öğleden sonra, yardıma ihtiyacınız var mı?`},{who: `you`, pt: `Sim, tenho dor de cabeça.`, tr: `Evet, başım ağrıyor.`},{who: `them`, pt: `Tem febre também?`, tr: `Ateşiniz de var mı?`},{who: `you`, pt: `Não, só dor de cabeça.`, tr: `Hayır, sadece baş ağrısı.`},{who: `them`, pt: `Este remédio pode ajudar.`, tr: `Bu ilaç yardımcı olabilir.`},{who: `you`, pt: `Preciso de receita?`, tr: `Reçete gerekiyor mu?`},{who: `them`, pt: `Não, não precisa.`, tr: `Hayır, gerekmiyor.`},{who: `you`, pt: `Como devo tomar?`, tr: `Nasıl almalıyım?`},{who: `them`, pt: `Um comprimido com água.`, tr: `Su ile bir hap.`},{who: `you`, pt: `Quantas vezes por dia?`, tr: `Günde kaç kez?`},{who: `them`, pt: `Duas vezes por dia, se precisar.`, tr: `Gerekirse günde iki kez.`},{who: `you`, pt: `Obrigado, foi muito gentil.`, tr: `Teşekkür ederim, çok naziktiniz.`}]},{id: 8, title: `Yerel biriyle küçük sohbet`, scene: `Porto’da nehir kenarında otururken yerel biriyle sohbet başlıyor. Şehir, yemek ve gezilecek yerler hakkında kısa ve samimi bir konuşma yapıyorsun.`, lines: [{who: `you`, pt: `Olá, esta cidade é muito bonita.`, tr: `Merhaba, bu şehir çok güzel.`},{who: `them`, pt: `Obrigado, você é turista?`, tr: `Teşekkürler, turist misiniz?`},{who: `you`, pt: `Sim, é minha primeira vez aqui.`, tr: `Evet, burada ilk kez bulunuyorum.`},{who: `them`, pt: `Está gostando do Porto?`, tr: `Porto’yu beğeniyor musunuz?`},{who: `you`, pt: `Sim, gosto muito daqui.`, tr: `Evet, burayı çok seviyorum.`},{who: `them`, pt: `Já provou a comida local?`, tr: `Yerel yemeği denediniz mi?`},{who: `you`, pt: `Ainda não, o que recomenda?`, tr: `Henüz hayır, ne önerirsiniz?`},{who: `them`, pt: `Recomendo uma francesinha.`, tr: `Francesinha öneririm.`},{who: `you`, pt: `Obrigado pela dica.`, tr: `Tavsiye için teşekkür ederim.`},{who: `them`, pt: `Também deve visitar a Ribeira.`, tr: `Ribeira’yı da ziyaret etmelisiniz.`},{who: `you`, pt: `Vou visitar amanhã.`, tr: `Yarın ziyaret edeceğim.`},{who: `them`, pt: `Boa viagem e aproveite.`, tr: `İyi yolculuklar ve keyfini çıkarın.`}]}];